SELECT
    *
FROM ing_outbox_message
WHERE channel = #{channel}
  AND dedup_key = #{dedupKey}
LIMIT 1

( SELECT * FROM ing_outbox_message WHERE status_code = 'PENDING'
AND channel = #{channel}
AND (not_before IS NULL OR not_before <= #{available}) AND (next_retry_at IS NULL OR next_retry_at <= #{available}) AND deleted = 0 ORDER BY id ASC LIMIT #{halfLimit} ) UNION ALL ( SELECT * FROM ing_outbox_message WHERE status_code = 'PUBLISHING'
AND channel = #{channel}
AND pub_leased_until < NOW(6) AND deleted = 0 ORDER BY id ASC LIMIT #{halfLimit} ) ORDER BY id ASC LIMIT #{limit}

